obstacle_input = input()
obstacle_list = obstacle_input.split()

obstacles = [0] * len(obstacle_list)

for i in range(len(obstacle_list)):
    obstacles[i] = int(obstacle_list[i])

non_zero_index = 0

for i in range(len(obstacles)):
    if obstacles[i] != 0:
        obstacles[non_zero_index] = obstacles[i]
        non_zero_index += 1

while non_zero_index < len(obstacles):
    obstacles[non_zero_index] = 0
    non_zero_index += 1

for i in range(len(obstacles)):
    if i != len(obstacles) - 1:
        print(obstacles[i], end=" ")
    else:
        print(obstacles[i])
